// Prereq in settings.js:
// functionGlobalContext: { moment: require("moment") }

const moment = global.get("moment");

if (!moment) {
  node.status({ fill: "red", shape: "ring", text: "moment not found" });
  msg.payload = {
    ok: false,
    error: "moment not available in functionGlobalContext",
    hint: "Edit settings.js: functionGlobalContext: { moment: require('moment') } and restart Node-RED"
  };
  return msg;
}

node.status({ fill: "green", shape: "dot", text: "moment ok" });
msg.payload = {
  ok: true,
  iso: moment().toISOString(),
  local: moment().format("YYYY-MM-DD HH:mm:ss"),
  note: "This is provided by functionGlobalContext"
};
return msg;
